"use strict";(self.webpackChunkmd_vuepress=self.webpackChunkmd_vuepress||[]).push([[6935],{3998:(n,s,a)=>{a.r(s),a.d(s,{data:()=>t});const t={key:"v-11e5ce84",path:"/react/react16.html",title:"十五分钟读懂 React 16",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"关联面试卡（快速跳转）",slug:"关联面试卡-快速跳转",children:[]},{level:2,title:"一、React 16 的三大里程碑式升级",slug:"一、react-16-的三大里程碑式升级",children:[{level:3,title:"✅ 1. Fiber 架构（核心底层重构）",slug:"✅-1-fiber-架构-核心底层重构",children:[]},{level:3,title:"✅ 2. 错误边界（Error Boundaries）",slug:"✅-2-错误边界-error-boundaries",children:[]},{level:3,title:"✅ 3. Portals（传送门）",slug:"✅-3-portals-传送门",children:[]}]},{level:2,title:"二、其他重要新特性",slug:"二、其他重要新特性",children:[{level:3,title:"🔸 Fragment（React.Fragment）",slug:"🔸-fragment-react-fragment",children:[]},{level:3,title:"🔸 支持直接返回字符串/数组",slug:"🔸-支持直接返回字符串-数组",children:[]},{level:3,title:"🔸 生命周期函数变更（铺垫未来）",slug:"🔸-生命周期函数变更-铺垫未来",children:[]},{level:3,title:"🔸 更好的服务器端渲染（SSR）",slug:"🔸-更好的服务器端渲染-ssr",children:[]}]},{level:2,title:"三、关键内部变化（开发者需知）",slug:"三、关键内部变化-开发者需知",children:[]},{level:2,title:"四、对现代 React 的影响",slug:"四、对现代-react-的影响",children:[]},{level:2,title:"五、15 分钟总结（速记版）",slug:"五、15-分钟总结-速记版",children:[]}],git:{updatedTime:1775721028e3},filePathRelative:"react/react16.md"}},5206:(n,s,a)=>{a.r(s),a.d(s,{default:()=>d});var t=a(6252);const e=(0,t._)("h1",{id:"十五分钟读懂-react-16",tabindex:"-1"},[(0,t._)("a",{class:"header-anchor",href:"#十五分钟读懂-react-16","aria-hidden":"true"},"#"),(0,t.Uk)(" 十五分钟读懂 React 16")],-1),p=(0,t._)("h2",{id:"关联面试卡-快速跳转",tabindex:"-1"},[(0,t._)("a",{class:"header-anchor",href:"#关联面试卡-快速跳转","aria-hidden":"true"},"#"),(0,t.Uk)(" 关联面试卡（快速跳转）")],-1),o=(0,t.Uk)("技术卡："),c=(0,t._)("code",null,"tech__react",-1),r=(0,t.Uk)("性能方法论："),l=(0,t._)("code",null,"tech__performance",-1),i=(0,t.uE)('<p>当然！虽然 React 16 发布于 2017 年（距今已有数年），但它引入了<strong>革命性的架构变革</strong>，是理解现代 React（包括 React 18+）的基础。用 <strong>15 分钟</strong>带你抓住 React 16 的<strong>核心突破</strong>，尤其适合你这样熟悉 React 但想系统梳理底层演进的前端开发者。</p><hr><h2 id="一、react-16-的三大里程碑式升级" tabindex="-1"><a class="header-anchor" href="#一、react-16-的三大里程碑式升级" aria-hidden="true">#</a> 一、React 16 的三大里程碑式升级</h2><h3 id="✅-1-fiber-架构-核心底层重构" tabindex="-1"><a class="header-anchor" href="#✅-1-fiber-架构-核心底层重构" aria-hidden="true">#</a> ✅ 1. <strong>Fiber 架构</strong>（核心底层重构）</h3><ul><li><strong>问题</strong>：React 15 及之前使用<strong>递归调和（Reconciliation）</strong>，一旦开始更新，必须<strong>同步完成整个组件树的 diff 和 DOM 操作</strong>，会阻塞主线程，导致卡顿（如输入卡、动画掉帧）。</li><li><strong>解决方案</strong>：引入 <strong>Fiber（Fiber Reconciler）</strong>，将更新过程<strong>拆分为可中断、可恢复的工作单元（fiber 节点）</strong>。 <ul><li>利用 <strong>requestIdleCallback</strong>（或 polyfill）在浏览器空闲时执行；</li><li>支持<strong>优先级调度</strong>（高优先级任务如用户输入可打断低优先级如数据加载）；</li><li>为<strong>异步渲染（Async Rendering）</strong> 奠定基础（后续的 Suspense、Concurrent Mode 都依赖它）。</li></ul></li></ul><blockquote><p>🔍 本质：Fiber 是一种<strong>带优先级的增量渲染机制</strong>，让 React 从“一次性做完”变为“分片执行”。</p></blockquote><hr><h3 id="✅-2-错误边界-error-boundaries" tabindex="-1"><a class="header-anchor" href="#✅-2-错误边界-error-boundaries" aria-hidden="true">#</a> ✅ 2. <strong>错误边界（Error Boundaries）</strong></h3><ul><li><p><strong>问题</strong>：React 15 中，组件内任何 JS 错误会导致<strong>整个应用崩溃（白屏）</strong>，且错误难以捕获。</p></li><li><p><strong>解决方案</strong>：引入生命周期 <code>componentDidCatch(error, info)</code>。</p><div class="language-jsx ext-jsx line-numbers-mode"><pre class="language-jsx"><code><span class="token keyword">class</span> <span class="token class-name">ErrorBoundary</span> <span class="token keyword">extends</span> <span class="token class-name">React<span class="token punctuation">.</span>Component</span> <span class="token punctuation">{</span>\n  state <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token literal-property property">hasError</span><span class="token operator">:</span> <span class="token boolean">false</span> <span class="token punctuation">}</span>\n\n  <span class="token function">componentDidCatch</span><span class="token punctuation">(</span><span class="token parameter">error<span class="token punctuation">,</span> info</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">this</span><span class="token punctuation">.</span><span class="token function">setState</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">hasError</span><span class="token operator">:</span> <span class="token boolean">true</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>\n    <span class="token function">logErrorToService</span><span class="token punctuation">(</span>error<span class="token punctuation">,</span> info<span class="token punctuation">.</span>componentStack<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n\n  <span class="token function">render</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">.</span>state<span class="token punctuation">.</span>hasError <span class="token operator">?</span> <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">FallbackUI</span></span> <span class="token punctuation">/&gt;</span></span> <span class="token operator">:</span> <span class="token keyword">this</span><span class="token punctuation">.</span>props<span class="token punctuation">.</span>children\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div></li><li><p><strong>限制</strong>：不能捕获<strong>事件处理函数</strong>、<strong>异步代码（setTimeout、Promise）</strong>、<strong>服务端渲染</strong>中的错误。</p></li></ul><blockquote><p>💡 这是你构建工单系统等企业应用时<strong>必备的容错机制</strong>。</p></blockquote><hr><h3 id="✅-3-portals-传送门" tabindex="-1"><a class="header-anchor" href="#✅-3-portals-传送门" aria-hidden="true">#</a> ✅ 3. <strong>Portals（传送门）</strong></h3><ul><li><strong>问题</strong>：Modal、Tooltip、Dropdown 等组件需要渲染到 <code>body</code> 下，但又想保留 React 组件的父子关系和事件冒泡。</li><li><strong>解决方案</strong>：<code>ReactDOM.createPortal(child, container)</code>。<div class="language-jsx ext-jsx line-numbers-mode"><pre class="language-jsx"><code><span class="token function">render</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">return</span> ReactDOM<span class="token punctuation">.</span><span class="token function">createPortal</span><span class="token punctuation">(</span>\n    <span class="token keyword">this</span><span class="token punctuation">.</span>props<span class="token punctuation">.</span>children<span class="token punctuation">,</span>\n    document<span class="token punctuation">.</span>body <span class="token comment">// 渲染到这里，但事件仍冒泡到父组件</span>\n  <span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div></li><li><strong>典型用途</strong>：弹窗、全屏加载、通知等。</li></ul><blockquote><p>🛠️ 在 Ant Design 中，<code>Modal</code> 和 <code>Drawer</code> 内部就大量使用 Portals。</p></blockquote><hr><h2 id="二、其他重要新特性" tabindex="-1"><a class="header-anchor" href="#二、其他重要新特性" aria-hidden="true">#</a> 二、其他重要新特性</h2><h3 id="🔸-fragment-react-fragment" tabindex="-1"><a class="header-anchor" href="#🔸-fragment-react-fragment" aria-hidden="true">#</a> 🔸 Fragment（React.Fragment）</h3><ul><li>解决“必须返回单个根元素”的限制：<div class="language-jsx ext-jsx line-numbers-mode"><pre class="language-jsx"><code><span class="token comment">// 以前：必须加 &lt;div&gt;</span>\n<span class="token comment">// 现在：</span>\n<span class="token function">render</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">return</span> <span class="token punctuation">(</span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">React.Fragment</span></span><span class="token punctuation">&gt;</span></span><span class="token plain-text">\n      </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">ChildA</span></span> <span class="token punctuation">/&gt;</span></span><span class="token plain-text">\n      </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">ChildB</span></span> <span class="token punctuation">/&gt;</span></span><span class="token plain-text">\n    </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span><span class="token class-name">React.Fragment</span></span><span class="token punctuation">&gt;</span></span>\n  <span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n<span class="token comment">// 或简写：</span>\n<span class="token keyword">return</span> <span class="token punctuation">(</span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span></span><span class="token punctuation">&gt;</span></span><span class="token plain-text">\n    </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">ChildA</span></span> <span class="token punctuation">/&gt;</span></span><span class="token plain-text">\n    </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">ChildB</span></span> <span class="token punctuation">/&gt;</span></span><span class="token plain-text">\n  </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span></span><span class="token punctuation">&gt;</span></span>\n<span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div></li></ul><hr><h3 id="🔸-支持直接返回字符串-数组" tabindex="-1"><a class="header-anchor" href="#🔸-支持直接返回字符串-数组" aria-hidden="true">#</a> 🔸 支持直接返回字符串/数组</h3><div class="language-jsx ext-jsx line-numbers-mode"><pre class="language-jsx"><code><span class="token comment">// React 16+</span>\n<span class="token function">render</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">return</span> <span class="token string">&#39;Hello&#39;</span><span class="token punctuation">;</span> <span class="token comment">// ✅ 合法</span>\n<span class="token punctuation">}</span>\n<span class="token function">render</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">return</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">.</span><span class="token function">map</span><span class="token punctuation">(</span><span class="token parameter">i</span> <span class="token operator">=&gt;</span> <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>li</span> <span class="token attr-name">key</span><span class="token script language-javascript"><span class="token script-punctuation punctuation">=</span><span class="token punctuation">{</span>i<span class="token punctuation">}</span></span><span class="token punctuation">&gt;</span></span><span class="token punctuation">{</span>i<span class="token punctuation">}</span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>li</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ✅ 合法</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><hr><h3 id="🔸-生命周期函数变更-铺垫未来" tabindex="-1"><a class="header-anchor" href="#🔸-生命周期函数变更-铺垫未来" aria-hidden="true">#</a> 🔸 生命周期函数变更（铺垫未来）</h3><ul><li><strong>废弃</strong>：<code>componentWillMount</code>、<code>componentWillReceiveProps</code>、<code>componentWillUpdate</code>（因 Fiber 异步特性，这些钩子可能被多次调用，不安全）。</li><li><strong>新增</strong>：<code>getDerivedStateFromProps</code>（静态方法，替代 <code>componentWillReceiveProps</code>）。</li></ul><blockquote><p>📌 虽然当时用得少，但为 React 16.3+ 的“严格模式”和后续 Hooks 铺路。</p></blockquote><hr><h3 id="🔸-更好的服务器端渲染-ssr" tabindex="-1"><a class="header-anchor" href="#🔸-更好的服务器端渲染-ssr" aria-hidden="true">#</a> 🔸 更好的服务器端渲染（SSR）</h3><ul><li>新增 <code>ReactDOM.hydrate()</code> 替代 <code>ReactDOM.render()</code> 用于注水（hydration）；</li><li>支持 <strong>Streaming SSR</strong>（通过 <code>renderToNodeStream</code>），可边生成 HTML 边发送，提升首屏速度。</li></ul><hr><h2 id="三、关键内部变化-开发者需知" tabindex="-1"><a class="header-anchor" href="#三、关键内部变化-开发者需知" aria-hidden="true">#</a> 三、关键内部变化（开发者需知）</h2><table><thead><tr><th>特性</th><th>React 15</th><th>React 16</th></tr></thead><tbody><tr><td>调和算法</td><td>Stack Reconciler（同步递归）</td><td><strong>Fiber Reconciler（异步分片）</strong></td></tr><tr><td>错误处理</td><td>全局崩溃</td><td><strong>Error Boundaries</strong></td></tr><tr><td>渲染目标</td><td>仅 DOM</td><td><strong>支持自定义渲染器（如 React Native、React ART）</strong></td></tr><tr><td>License</td><td>BSD + Patents（争议）</td><td><strong>MIT（2017 年 9 月后）</strong></td></tr></tbody></table><blockquote><p>💡 React 16 的 MIT 许可证使其在企业（如你的 Backstage 插件）中更安全地使用。</p></blockquote><hr><h2 id="四、对现代-react-的影响" tabindex="-1"><a class="header-anchor" href="#四、对现代-react-的影响" aria-hidden="true">#</a> 四、对现代 React 的影响</h2><p>React 16 是<strong>承上启下的关键版本</strong>：</p><ul><li><strong>Fiber 架构</strong> → 支撑了 React 18 的 <strong>Concurrent Rendering</strong>、<strong>Automatic Batching</strong>；</li><li><strong>Portals + Error Boundaries</strong> → 成为企业级应用的标配；</li><li><strong>MIT 许可</strong> → 促使 Facebook、Airbnb、微软等大规模采用。</li></ul><hr><h2 id="五、15-分钟总结-速记版" tabindex="-1"><a class="header-anchor" href="#五、15-分钟总结-速记版" aria-hidden="true">#</a> 五、15 分钟总结（速记版）</h2><table><thead><tr><th>核心突破</th><th>作用</th><th>你的项目是否用到？</th></tr></thead><tbody><tr><td><strong>Fiber</strong></td><td>异步可中断渲染，提升性能</td><td>✅ 所有现代 React 应用底层都依赖它</td></tr><tr><td><strong>Error Boundaries</strong></td><td>捕获组件错误，防止白屏</td><td>✅ 工单系统建议包裹关键模块</td></tr><tr><td><strong>Portals</strong></td><td>渲染到任意 DOM 节点</td><td>✅ Ant Design Modal 依赖它</td></tr><tr><td><strong>Fragment</strong></td><td>无需额外 div 包裹</td><td>✅ 日常开发高频使用</td></tr><tr><td><strong>MIT License</strong></td><td>消除专利风险</td><td>✅ 企业项目合规性保障</td></tr></tbody></table><hr><blockquote><p>🕒 你已经用不到 15 分钟掌握了 React 16 的精髓！</p></blockquote><p>如果你接下来想了解 <strong>React 18 的并发特性</strong>（如 <code>useTransition</code>、<code>Suspense for Data Fetching</code>）如何在你的 <code>my-ticket-agent</code> 中提升用户体验，也可以告诉我！</p>',42),u={},d=(0,a(3744).Z)(u,[["render",function(n,s){const a=(0,t.up)("RouterLink");return(0,t.wg)(),(0,t.iD)(t.HY,null,[e,p,(0,t._)("ul",null,[(0,t._)("li",null,[o,(0,t.Wm)(a,{to:"/interview-prep/tech__react.html#%E5%8E%9F%E7%90%86%E7%AE%80%E8%BF%B0"},{default:(0,t.w5)((()=>[c])),_:1})]),(0,t._)("li",null,[r,(0,t.Wm)(a,{to:"/interview-prep/tech__performance.html#%E5%8E%9F%E7%90%86%E7%AE%80%E8%BF%B0"},{default:(0,t.w5)((()=>[l])),_:1})])]),i],64)}]])}}]);